                for (int j = 0; j < R; j++) {
                    // Release resources of process i
                    available[j] += allocation[i][j];  
                }
                safeSeq[count++] = i;    // Add process i to the safe sequence
                finished[i] = true;      // Mark process i as finished
                found = true;            // A valid process was found in this pass
            }
        }
    }

    // If no unfinished process could run, the system is in an unsafe state
    if (!found) {
        System.out.println("System is in an UNSAFE state.");
        return;
    }
}
